import { Request, Response } from 'express';
import { StudentService } from '@/application/services/student.service';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';
import { LICENSE_CATEGORIES } from '@/domain/constants/student.constants';
import { LicenseCategoryModel } from '@/infrastructure/database/models/license_category.model';
import { ctrlLogger } from '@/infrastructure/logging/controller-logger';
import { ExcelHelper } from '@/infrastructure/utils/excel.helper';

// Initialize the service cleanly
const studentService = new StudentService();

export const createStudent = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.create', req);
  log.start({});

  // Ensure teacher_id is tied to the current user if they are a teacher
  if (req.user?.role === 'teacher') {
    req.body.teacher_id = req.user.id || req.user._id;
  }

  const student = await studentService.createStudent(req.body, req.user);
  log.success(res as any, student, 'Tạo học viên thành công');
});

export const getAllStudents = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.get_all', req);
  log.start({ query: req.query });

  const filters = { ...req.query };
  const pagination = req.pagination || { page: 1, limit: 10 };
  const students = await studentService.getAllStudents(filters, pagination, req.user);
  log.success(res, students, 'Lấy danh sách học viên thành công');
});

export const getStudentById = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.get_by_id', req);
  const idStr = typeof req.params.id === 'string' ? req.params.id : (req.params.id as string[])[0];
  log.start({ studentId: idStr });

  const student = await studentService.getStudentById(idStr, req.user);
  log.success(res, student, 'Lấy thông tin học viên thành công');
});

export const updateStudent = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.update', req);
  const idStr = typeof req.params.id === 'string' ? req.params.id : (req.params.id as string[])[0];
  log.start({ studentId: idStr });

  // Resource validation via service/repo
  await studentService.getStudentById(idStr, req.user);

  const updated = await studentService.updateStudent(idStr, req.body);
  log.success(res, updated, 'Cập nhật học viên thành công');
});

export const deleteStudent = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.delete', req);
  const idStr = typeof req.params.id === 'string' ? req.params.id : (req.params.id as string[])[0];
  log.start({ studentId: idStr });

  const deleted = await studentService.deleteStudent(idStr, req.user);
  log.success(res, deleted, 'Xóa học viên thành công');
});

export const bulkDeleteStudents = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.bulkDelete', req);
  const { ids } = req.body;
  log.start({ count: ids?.length });

  await studentService.bulkDeleteStudents(ids, req.user);
  log.success(res, null, `Đã xóa thành công ${ids.length} học viên`);
});

export const getStudentHistory = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('student.history', req);
  const idStr = typeof req.params.id === 'string' ? req.params.id : (req.params.id as string[])[0];
  log.start({ studentId: idStr });

  // Resource validation
  await studentService.getStudentById(idStr, (req as any).user);

  const pagination = (req as any).pagination || { page: 1, limit: 20 };
  const history = await studentService.getStudentHistory(idStr, pagination);
  log.success(res as any, history, 'Lấy lịch sử học viên thành công');
});

export const getLicenseCategories = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('student.license_categories', req);
  log.start({});

  const categories = await LicenseCategoryModel.find({}).sort({ name: 1 }).exec();
  log.success(res as any, categories, 'Lấy danh mục hạng bằng thành công');
});

export const exportStudents = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.export', req);
  const filters = { ...req.query };

  log.start({ query: filters });

  await studentService.exportStudentsToExcel(res, filters, req.user);
});

export const importStudents = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.import', req);
  if (!(req as any).file) {
    return log.fail('missing_file', res, 400, 'Không tìm thấy file tải lên');
  }

  log.start({ fileName: (req as any).file.originalname, userId: req.user?.id });

  const courseId = req.body.course_id;
  const importType = req.body.import_type || 'student_only';
  const userId = req.user?.id || req.user?._id;
  const userRole = req.user?.role;

  // Use type assertion to bypass stale TS warnings if any
  const results = await (studentService as any).importStudentsFromExcel(
    (req as any).file.path,
    userId,
    userRole,
    courseId,
    importType,
  );

  log.success(res as any, results, 'Quá trình nhập dữ liệu học viên đã được bắt đầu trong nền');
});

export const downloadTemplate = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.download_template', req);
  const type = req.query.type as 'student_only' | 'student_and_course' || 'student_only';
  log.start({ type });

  const excelHelper = new ExcelHelper();
  await excelHelper.getImportTemplate(res, type);
});

export const getImportStats = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('student.get_import_stats', req);
  log.start({});

  const stats = await studentService.getImportManagementStats(req.user);
  log.success(res as any, stats, 'Lấy thống kê nhập liệu thành công');
});

export const getLeads = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('student.get_leads', req);
  log.start({});

  const leads = await studentService.getLeads();
  log.success(res as any, leads, 'Lấy danh sách lead thành công');
});

